#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
CI mx=5e5+5;
int f[mx][26],n,m,d[mx],s[mx],w[mx];
vector<int>g[mx];
void dfs(int u,int fa)
{
	d[u]=d[fa]+1;//深度
	f[u][0]=fa;
	s[u]=s[fa]+w[u];//距离
	FOR(i,1,25)
	{
		f[u][i]=f[f[u][i-1]][i-1];//树上倍增
	}
	FOI(v,g[u])
	{
		if(v==fa)
		{
			continue;
		}
		dfs(v,u);
	}
}
int lca(int x,int y)//最佳公共祖先
{
	if(d[x]<d[y])
	{
		swap(x,y);
	}
	ROF(i,25,0)
	{
		if(d[f[x][i]]>=d[y])
		{
			x=f[x][i];
		}
	}
	if(x==y)
	{
		return x;
	}
	ROF(i,25,0)
	{
		if(f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
signed main(void)
{
	IOS
	cin>>n>>m;
	FOR(i,1,n-1)
	{
		int u,v;
		cin>>u>>v;
		g[u].pb(v);
		g[v].pb(u);
		w[u]++;
		w[v]++;
	}
	dfs(1,0);
	FOR(i,1,m)
	{
		int u,v;
		cin>>u>>v;
		int l=lca(u,v);
		int ans=s[u]+s[v]-s[l]-s[f[l][0]];
		cout<<ans<<'\n';
	}
	return false;
}
